import { Layer, Source } from '@vis.gl/react-maplibre';
import { type PropsWithChildren } from 'react';

import { _useBehavioralTrackingProps as useBehavioralTrackingProps } from '@dynatrace/strato-components/core';

import { ChoroplethLayerTooltip } from './ChoroplethLayerTooltip.js';
import { ChoroplethOutlineLayer } from './ChoroplethOutlineLayer.js';
import { parseRegionDataToGeoJSON } from './utils/parse-region-data-to-geo-json.js';
import {
  DEFAULT_CHOROPLETH_COLOR,
  SHAPE_OPACITY_DIMMED,
  SHAPE_OPACITY_DEFAULT,
} from '../../constants.js';
import { useLayerColoringStrategy } from '../../hooks/use-layer-coloring-strategy.js';
import { useLegendInteractionHighlighting } from '../../hooks/use-legend-interaction-highlighting.js';
import { useLegendInteractionVisibility } from '../../hooks/use-legend-interaction-visibility.js';
import { useMapBaseLayerFeatures } from '../../hooks/use-map-base-layer-features.js';
import { useResolveChoroplethColor } from '../../hooks/use-resolve-color.js';
import { useTooltipTemplate } from '../../hooks/use-tooltip-template.js';
import { ChoroplethLayerTooltip as ChoroplethLayerTooltipSlot } from '../../slots/ChoroplethLayerTooltip.js';
import type { InternalChoroplethLayerProps } from '../../types/choropleth-layer.js';
import { isChoroplethTooltipTemplate } from '../../utils/tooltip-type-guards.js';
import { TooltipWrapper } from '../TooltipWrapper.js';

export const ChoroplethLayer = <T extends Record<string, unknown>>(
  props: PropsWithChildren<InternalChoroplethLayerProps<T>>,
) => {
  const { layerId, data, regionAccessor, children } = props;
  const [behavioralTrackingProps] = useBehavioralTrackingProps(props);
  const mapSource = useMapBaseLayerFeatures();

  const colorParser = useLayerColoringStrategy();
  const choroplethColor = useResolveChoroplethColor(
    DEFAULT_CHOROPLETH_COLOR,
    props,
    colorParser,
  );
  const sourceId = layerId.replace('layer', 'source');
  useLegendInteractionHighlighting(props, sourceId);
  useLegendInteractionVisibility(props, layerId);

  const dataGeoJSON =
    mapSource &&
    parseRegionDataToGeoJSON(mapSource, data, regionAccessor, choroplethColor);

  const {
    handler: tooltipTemplate,
    hidden: tooltipHidden,
    symbolAlignment,
  } = useTooltipTemplate(children, ChoroplethLayerTooltipSlot, {
    extractProps: true,
  });

  return (
    dataGeoJSON && (
      <Source id={sourceId} type="geojson" data={dataGeoJSON} generateId>
        <Layer
          id={layerId}
          source={sourceId}
          type="fill"
          paint={{
            'fill-color': ['get', '__color'],
            'fill-opacity': [
              'case',
              ['==', ['feature-state', 'legendHover'], false],
              SHAPE_OPACITY_DIMMED,
              ['==', ['feature-state', 'active'], true],
              SHAPE_OPACITY_DEFAULT,
              ['==', ['feature-state', 'hover'], true],
              SHAPE_OPACITY_DEFAULT,
              ['==', ['feature-state', 'legendHover'], true],
              SHAPE_OPACITY_DEFAULT,
              ['==', ['feature-state', 'isAnyActive'], true],
              SHAPE_OPACITY_DIMMED,
              SHAPE_OPACITY_DEFAULT,
            ],
          }}
          {...behavioralTrackingProps}
        />
        <ChoroplethOutlineLayer sourceId={sourceId} />
        <TooltipWrapper layerId={layerId}>
          <ChoroplethLayerTooltip
            tooltipTemplate={
              isChoroplethTooltipTemplate(tooltipTemplate)
                ? tooltipTemplate
                : undefined
            }
            hidden={tooltipHidden}
            symbolAlignment={symbolAlignment}
          />
        </TooltipWrapper>
      </Source>
    )
  );
};

ChoroplethLayer['displayName'] = 'ChoroplethLayer';
